const incomingKey = $('Webhook').first().json.body.developer_api_key;

const developers = items.map(i => i.json);

const dev = developers.find(
  d => d.developer_api_key === incomingKey
);

if (!dev) {
  return [
    {
      json: {
        error: "Wrong developer_api_key"
      }
    }
  ];
}

if (dev.status !== "active") {
  return [
    {
      json: {
        error: "Developer access disabled"
      }
    }
  ];
}

return [
  {
    json: {
      developer_name: dev.developer_name,
      developer_api_key: dev.developer_api_key,
      prompt: $('Webhook').first().json.body.prompt,
      type: $('Webhook').first().json.body.type,
      reference_image_url: $('Webhook').first().json.body.reference_image_url || null,
      image_count: $('Webhook').first().json.body.image_count || null,
      video_duration: $('Webhook').first().json.body.video_duration || null,
      model: $('Webhook').first().json.body.model      
    }
  }
];

const items = $input.all();

if (items.length === 0) {
  throw new Error('No rows found');
}

const randomIndex = Math.floor(Math.random() * items.length);

return [items[randomIndex]];

